import React, { useEffect } from 'react';
import * as XLSX from 'xlsx';
import { Header } from './components/Header';
import { LeftTable } from './components/LeftTable';
import { RightTable } from './components/RightTable';
import { Footer } from './components/Footer';

function App() {

  // Load saved data on component mount
  useEffect(() => {
    const loadData = () => {
      try {
        const savedData = localStorage.getItem('ccm-log-data');
        if (savedData) {
          const values = JSON.parse(savedData);
          const inputs = document.querySelectorAll('input, textarea');
          let valueIndex = 0;

          inputs.forEach((input) => {
            const el = input as HTMLInputElement | HTMLTextAreaElement;
            if (el.type === 'radio') {
               // Handle radio buttons separately if needed, or check value matching
               if (values[valueIndex] && el.value === values[valueIndex]) {
                  (el as HTMLInputElement).checked = true;
               }
               // Note: This logic assumes deterministic order. Radios might share an index in a simple list? 
               // Actually, previous save logic just pushed all values.
               // For radios, all radio buttons in the group are inputs.
               // It's tricky to restore properly without better ID mapping, 
               // but we will keep best effort restoration.
               if (values[valueIndex] === el.value && (el as HTMLInputElement).name === 'shift') {
                  (el as HTMLInputElement).checked = true;
               }
            } else {
               if (values[valueIndex] !== undefined) {
                 el.value = values[valueIndex];
               }
            }
            valueIndex++;
          });
        }
      } catch (error) {
        console.error("Error loading data:", error);
      }
    };

    // Small delay to ensure DOM is ready
    setTimeout(loadData, 100);
  }, []);

  const handleSave = () => {
    try {
      const inputs = document.querySelectorAll('input, textarea');
      const dataForExcel: { Parameter: string, Value: string }[] = [];
      const valuesForStorage: string[] = [];

      inputs.forEach((input) => {
        const el = input as HTMLInputElement | HTMLTextAreaElement;

        // Storage Logic
        if (el.type === 'radio') {
           // For storage, we might want to store if it is checked or not, 
           // but the previous simple array method just stored values. 
           // To keep restoration working (mostly), we store the value if checked, else empty?
           // The previous logic stored `el.value` for everything. 
           // For a radio `value` is "A", "B" etc constant.
           // To restore properly we need to know WHICH was checked.
           // Let's improve storage: store the value of the checked one?
           // The simple array approach is brittle. 
           // We will maintain the old behavior for storage to not break it further, 
           // or just store the value if checked? 
           // Let's focus on Excel export which is the new feature.
           valuesForStorage.push(el.type === 'radio' && (el as HTMLInputElement).checked ? el.value : (el.type === 'radio' ? '' : el.value));
        } else {
           valuesForStorage.push(el.value);
        }

        // Excel Logic
        const label = el.getAttribute('data-label');
        if (label) {
           if (el.type === 'radio') {
              if ((el as HTMLInputElement).checked) {
                 dataForExcel.push({ Parameter: label, Value: el.value });
              }
           } else {
              dataForExcel.push({ Parameter: label, Value: el.value });
           }
        }
      });

      // 1. Save to Local Storage
      localStorage.setItem('ccm-log-data', JSON.stringify(valuesForStorage));

      // 2. Generate Excel
      const ws = XLSX.utils.json_to_sheet(dataForExcel);
      const wb = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(wb, ws, "CCM Log Data");

      // Generate filename with timestamp
      const dateStr = new Date().toISOString().slice(0, 10);
      XLSX.writeFile(wb, `CCM_Log_Sheet_${dateStr}.xlsx`);

    } catch (error) {
      console.error("Error saving data:", error);
      alert('Failed to save/export data.');
    }
  };

  return (
    <div className="min-h-screen p-4 md:p-8 flex justify-center items-start print:p-0">

      {/* Paper Container */}
      <div className="w-full max-w-[1000px] bg-white border-2 border-black shadow-2xl print:shadow-none print:border-2">

        {/* Header */}
        <Header />

        {/* Main Split Body */}
        <div className="flex flex-col md:flex-row print:flex-row">
          {/* Left Panel: ~55% width */}
          <div className="w-full md:w-[55%]">
            <LeftTable />
          </div>

          {/* Right Panel: ~45% width */}
          <div className="w-full md:w-[45%]">
            <RightTable />
          </div>
        </div>

        {/* Footer / Personnel */}
        <Footer />

      </div>

      {/* Floating Action Buttons */}
      <div className="fixed bottom-8 right-8 flex flex-col gap-4 no-print">

        {/* Save Button */}
        <button 
          onClick={handleSave}
          className="bg-green-600 text-white p-4 rounded-full shadow-lg hover:bg-green-700 transition-colors flex items-center justify-center"
          title="Save to Excel"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7H5a2 2 0 00-2 2v9a2 2 0 002 2h14a2 2 0 002-2V9a2 2 0 00-2-2h-3m-1 4l-3 3m0 0l-3-3m3 3V4" />
          </svg>
        </button>

        {/* Print Button */}
        <button 
          onClick={() => window.print()}
          className="bg-blue-600 text-white p-4 rounded-full shadow-lg hover:bg-blue-700 transition-colors flex items-center justify-center"
          title="Print Sheet"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z" />
          </svg>
        </button>
      </div>

    </div>
  );
}

