import React, { useEffect, useState } from 'react';
import * as XLSX from 'xlsx';
import { Header } from './components/Header';
import { LeftTable } from './components/LeftTable';
import { RightTable } from './components/RightTable';
import { Footer } from './components/Footer';

function App() {
  const [historyCount, setHistoryCount] = useState(0);

  // Load saved data (current draft) on component mount
  useEffect(() => {
    const loadData = () => {
      try {
        // 1. Load Draft State (Visual Inputs)
        const savedData = localStorage.getItem('ccm-log-data');
        if (savedData) {
          const values = JSON.parse(savedData);
          const inputs = document.querySelectorAll('input, textarea');
          let valueIndex = 0;

          inputs.forEach((input) => {
            const el = input as HTMLInputElement | HTMLTextAreaElement;
            if (el.type === 'radio') {
               // Handle radio buttons restoration logic
               if (values[valueIndex] === el.value) {
                  (el as HTMLInputElement).checked = true;
               } else if (values[valueIndex] === '') {
                   (el as HTMLInputElement).checked = false;
               }
            } else {
               if (values[valueIndex] !== undefined) {
                 el.value = values[valueIndex];
               }
            }
            valueIndex++;
          });
        }

        // 2. Load History Count
        const historyJson = localStorage.getItem('ccm-log-history');
        if (historyJson) {
          setHistoryCount(JSON.parse(historyJson).length);
        }
      } catch (error) {
        console.error("Error loading data:", error);
      }
    };

    // Small delay to ensure DOM is ready
    setTimeout(loadData, 100);
  }, []);

  // Helper to collect current form data into a key-value map
  const getFormDataMap = () => {
    const inputs = document.querySelectorAll('input, textarea');
    const dataMap: Record<string, string> = {};

    inputs.forEach((input) => {
      const el = input as HTMLInputElement | HTMLTextAreaElement;
      const label = el.getAttribute('data-label');
      if (label) {
         if (el.type === 'radio') {
            if ((el as HTMLInputElement).checked) {
               dataMap[label] = el.value;
            }
         } else {
            dataMap[label] = el.value;
         }
      }
    });
    return dataMap;
  };

  // Helper to save current draft state (array of values) for page reload persistence
  const saveDraftState = () => {
     const inputs = document.querySelectorAll('input, textarea');
     const valuesForStorage: string[] = [];
     inputs.forEach((input) => {
        const el = input as HTMLInputElement | HTMLTextAreaElement;
        if (el.type === 'radio') {
           valuesForStorage.push((el as HTMLInputElement).checked ? el.value : '');
        } else {
           valuesForStorage.push(el.value);
        }
     });
     localStorage.setItem('ccm-log-data', JSON.stringify(valuesForStorage));
  };

  // Helper to generate the Excel Rows (AOA) for a single data entry
  const generateEntryRows = (dataMap: Record<string, string>) => {
      const aoa: (string | number | null)[][] = [];

      // --- Header Section ---
      aoa.push(["WELSPUN CORP LTD (STEEL DIVISION)"]);
      aoa.push(["CCM LOG SHEET"]);
      aoa.push([]); // Spacer

      aoa.push([
        "DATE", dataMap["DATE"] || "", 
        "SHIFT", dataMap["SHIFT"] || ""
      ]);
      aoa.push([
        "HEAT NO", dataMap["HEAT NO"] || "", 
        "CAST NO", dataMap["CAST NO"] || ""
      ]);
      aoa.push(["SHIFT IN CHARGE", dataMap["SHIFT IN CHARGE"] || ""]);
      aoa.push([]); // Spacer

      // --- Main Table Headers ---
      aoa.push(["PARAMETER", "STD 1 / VALUE", "STD 2"]);

      // Helper to add data rows safely
      const addRow = (label: string, isSplit: boolean = false) => {
        if (isSplit) {
            aoa.push([
                label, 
                dataMap[`${label} (STD 1)`] || "", 
                dataMap[`${label} (STD 2)`] || ""
            ]);
        } else {
             aoa.push([
                label, 
                dataMap[label] || "", 
                ""
            ]);
        }
      };

      // --- Process Parameters ---
      aoa.push(["--- PROCESS PARAMETERS ---"]);

      const leftSplitItems = [
        "TUNDISH NO", "TUNDISH BOARD", "TUNDISH LIFE", "TUNDISH NOZZLE DIA",
        "TUNDISH OPENING", "MOULD JACKET NO", "SECTION", "MOULD TUBE NO",
        "MOULD TUBE LIFE", "MOULD TUBE CLEANING LIFE", "CASTING START TIME",
        "CASTING FINISH TIME", "TOTAL CASTING TIME", "AVG CASTING SPEED"
      ];
      leftSplitItems.forEach(item => addRow(item, true));

      addRow("RAPSEED OIL / CASTING POWDER", false);
      addRow("RHOMBOIDITY", true);
      addRow("PRIMARY MOULD WATER", true);

      aoa.push(["PRIMARY MOULD WATER PRESSURE"]);
      aoa.push([
          "   INLET", 
          dataMap["PRIMARY MOULD WATER PRESSURE - INLET (STD 1)"] || "", 
          dataMap["PRIMARY MOULD WATER PRESSURE - INLET (STD 2)"] || ""
      ]);
      aoa.push([
          "   OUTLET", 
          dataMap["PRIMARY MOULD WATER PRESSURE - OUTLET (STD 1)"] || "", 
          dataMap["PRIMARY MOULD WATER PRESSURE - OUTLET (STD 2)"] || ""
      ]);

      aoa.push(["PRIMARY WATER TEMP"]);
      aoa.push([
          "   INLET", 
          dataMap["PRIMARY WATER TEMP - INLET (STD 1)"] || "", 
          dataMap["PRIMARY WATER TEMP - INLET (STD 2)"] || ""
      ]);
      aoa.push([
          "   OUTLET", 
          dataMap["PRIMARY WATER TEMP - OUTLET (STD 1)"] || "", 
          dataMap["PRIMARY WATER TEMP - OUTLET (STD 2)"] || ""
      ]);

      aoa.push(["SECONDARY WATER (L/min)"]);
      addRow("ZONE 1", true);
      addRow("ZONE 2", true);
      addRow("ZONE 3", true);

      aoa.push([]);

      // --- Timings & Checks ---
      aoa.push(["--- TIMINGS & CHECKS ---"]);

      const rightSingleItems = [
        "LRF TIMING", "TAPPING TIME", "PURGING TIME", "LIFTING TEMP", "TUNDISH TEMP",
        "LADLE NO", "LADLE LIFE", "LADLE OPENING", "LADLE OPEN TIME", "LADLE CLOSE TIME",
        "MBS/SEN HEATING TIME FROM", "MBS/SEN HEATING TIME TO"
      ];
      rightSingleItems.forEach(item => addRow(item, false));

      addRow("TOTAL NO OF BILLET", true);
      addRow("TOTAL WT", false);
      addRow("LADLE SHROUD LIFE", false);
      addRow("MBS LIFE", false);
      addRow("BILLET LENGTH", true);

      const rightSingleItems2 = [
        "CHECK LIST", "WITHDRAWAL ROLL STRAIGHTENER PRESSURE", "HYD PRESSURE",
        "TOCB", "CROSS TRANSFER TROLLEY", "R D B G", "BELLOW AIR PRESSURE",
        "CASTING COMPLETED AT", "MACHINE READY AT"
      ];
      rightSingleItems2.forEach(item => addRow(item, false));

      aoa.push([]);
      aoa.push(["REMARKS", dataMap["REMARKS"] || ""]);
      aoa.push([]);

      // --- Personnel ---
      aoa.push(["--- PERSONNEL ---"]);
      addRow("MOULD OPERATOR", true);
      addRow("FITTER / SHIFT FITTER", false);
      addRow("S B O", false);
      addRow("GAS CUTTER", true);
      addRow("TEEMER MAN", false);

      return aoa;
  };

  const handleSave = () => {
    try {
      // 1. Save current state to local storage (Draft)
      saveDraftState();

      // 2. Get Data Map for History
      const currentDataMap = getFormDataMap();

      // 3. Get existing history
      const historyJson = localStorage.getItem('ccm-log-history');
      let history: Record<string, string>[] = [];
      if (historyJson) {
         try {
            history = JSON.parse(historyJson);
         } catch (e) {
            console.error("Failed to parse history", e);
            history = [];
         }
      }

      // 4. Append new entry
      history.push(currentDataMap);
      localStorage.setItem('ccm-log-history', JSON.stringify(history));
      setHistoryCount(history.length);

      // 5. Generate Master Excel Sheet
      let masterAOA: (string | number | null)[][] = [];
      let merges: any[] = [];
      let currentRowIndex = 0;

      // Iterate through all history entries and stack them
      history.forEach((entry, index) => {
         // Add visual separator for appended entries
         if (index > 0) {
            masterAOA.push(
               [], 
               [`=== ENTRY #${index + 1} ======================================`], 
               [],
            );
            currentRowIndex += 3;
         } else {
             // For the first entry, we can add a small label or just start
             // masterAOA.push(["ENTRY #1"]);
             // currentRowIndex += 1;
         }

         const entryAOA = generateEntryRows(entry);

         // Calculate Merges for the Title in this specific block
         // Title is at Relative Row 0, Subtitle at Relative Row 1
         merges.push({ s: { r: currentRowIndex + 0, c: 0 }, e: { r: currentRowIndex + 0, c: 2 } });
         merges.push({ s: { r: currentRowIndex + 1, c: 0 }, e: { r: currentRowIndex + 1, c: 2 } });

         // Add to Master
         masterAOA = masterAOA.concat(entryAOA);
         currentRowIndex += entryAOA.length;
      });

      // 6. Create Sheet
      const ws = XLSX.utils.aoa_to_sheet(masterAOA);

      // Set Column Widths
      ws['!cols'] = [
        { wch: 40 }, // Parameter Column
        { wch: 25 }, // STD 1 / Value
        { wch: 25 }, // STD 2
      ];

      // Apply Dynamic Merges
      ws['!merges'] = merges;

      const wb = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(wb, ws, "CCM Log History");

      // Generate filename
      const dateStr = new Date().toISOString().slice(0, 10);
      XLSX.writeFile(wb, `CCM_Log_Sheet_${dateStr}_(${history.length}_Entries).xlsx`);

    } catch (error) {
      console.error("Error saving data:", error);
      alert('Failed to save data.');
    }
  };

  const handleClearForm = () => {
      const inputs = document.querySelectorAll('input, textarea');
      inputs.forEach((input) => {
        const el = input as HTMLInputElement | HTMLTextAreaElement;
        if (el.type === 'radio') {
            (el as HTMLInputElement).checked = false;
        } else {
            el.value = '';
        }
      });
      // Clear draft in storage too so it doesn't come back on reload
      localStorage.removeItem('ccm-log-data');
  };

  const handleResetHistory = () => {
      if (confirm("Are you sure? This will delete the Excel history (Entry #1, Entry #2...). This cannot be undone.")) {
          localStorage.removeItem('ccm-log-history');
          setHistoryCount(0);
          alert("History cleared. Next save will be Entry #1.");
      }
  };

  return (
    <div className="min-h-screen p-4 md:p-8 flex justify-center items-start print:p-0">

      {/* Paper Container */}
      <div className="w-full max-w-[1000px] bg-white border-2 border-black shadow-2xl print:shadow-none print:border-2">

        {/* Header */}
        <Header />

        {/* Main Split Body */}
        <div className="flex flex-col md:flex-row print:flex-row">
          {/* Left Panel: ~55% width */}
          <div className="w-full md:w-[55%]">
            <LeftTable />
          </div>

          {/* Right Panel: ~45% width */}
          <div className="w-full md:w-[45%]">
            <RightTable />
          </div>
        </div>

        {/* Footer / Personnel */}
        <Footer />

      </div>

      {/* Floating Action Buttons */}
      <div className="fixed bottom-8 right-8 flex flex-col gap-3 no-print items-end">

        {/* Status Badge */}
        {historyCount > 0 && (
            <div className="bg-gray-800 text-white text-xs px-3 py-1 rounded-full shadow-md mb-2">
                {historyCount} Entr{historyCount === 1 ? 'y' : 'ies'} in File
            </div>
        )}

        {/* Save Button (Green) */}
        <button 
          onClick={handleSave}
          className="bg-green-600 text-white p-4 rounded-full shadow-lg hover:bg-green-700 transition-colors flex items-center justify-center group relative"
          title="Save & Append to Excel"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7H5a2 2 0 00-2 2v9a2 2 0 002 2h14a2 2 0 002-2V9a2 2 0 00-2-2h-3m-1 4l-3 3m0 0l-3-3m3 3V4" />
          </svg>
          <span className="absolute right-full mr-2 bg-gray-800 text-white text-xs px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
             Save & Append
          </span>
        </button>

        {/* Clear Form Button (Orange) */}
        <button 
          onClick={handleClearForm}
          className="bg-orange-500 text-white p-3 rounded-full shadow-lg hover:bg-orange-600 transition-colors flex items-center justify-center group relative"
          title="Clear Form for New Entry"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
          </svg>
          <span className="absolute right-full mr-2 bg-gray-800 text-white text-xs px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
             New Entry
          </span>
        </button>

        {/* Reset History Button (Red) */}
        <button 
          onClick={handleResetHistory}
          className="bg-red-600 text-white p-3 rounded-full shadow-lg hover:bg-red-700 transition-colors flex items-center justify-center group relative"
          title="Reset Excel History"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
          </svg>
           <span className="absolute right-full mr-2 bg-gray-800 text-white text-xs px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
             Reset File
          </span>
        </button>

        {/* Print Button (Blue) */}
        <button 
          onClick={() => window.print()}
          className="bg-blue-600 text-white p-3 rounded-full shadow-lg hover:bg-blue-700 transition-colors flex items-center justify-center group relative"
          title="Print Sheet"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z" />
          </svg>
        </button>
      </div>

    </div>
  );
